import React from "react";
import { ArrowLeft } from "lucide-react";

export default function PaymentSuccessScreen({ onBack, transaction }) {
  return (
    <div className="min-h-screen bg-[#f4f6fb] px-5 pt-6 pb-24 flex flex-col items-center gap-6">
      <button onClick={onBack} className="self-start mb-8">
        <ArrowLeft className="w-6 h-6 text-gray-700" />
      </button>

      <div className="bg-white rounded-2xl p-6 shadow-sm flex flex-col items-center gap-4">
        <p className="text-2xl font-semibold text-emerald-600">
          Payment Successful
        </p>

        <p className="text-gray-900 text-lg">
          ₦{transaction.amount.toLocaleString()}
        </p>

        <p className="text-gray-500 text-sm">
          Reference: {transaction.reference}
        </p>
      </div>
    </div>
  );
}
